import play.api.mvc._
import slick.jdbc.PostgresProfile.api._
import scala.concurrent.ExecutionContext.Implicits.global
import scala.concurrent.Future

case class Product(id: Int, name: String, price: Double)

class ProductController @Inject()(db: Database) extends Controller {

  def searchProducts = Action.async { request =>
    val queryParams = request.queryString

    // Constructing the SQL query with dynamic WHERE clauses
    val sqlFragment = {
      val conditions = Seq(
        queryParams.get("name").map(names => s"name LIKE '%${names.mkString("%' OR name LIKE '")}%'.stripSuffix("OR")),
        queryParams.get("minPrice").map(minPrice => s"price >= ${minPrice.head}"),
        queryParams.get("maxPrice").map(maxPrice => s"price <= ${maxPrice.head}")
      ).flatten

      conditions match {
        case Nil => ""
        case _   => conditions.mkString(" AND ")
      }
    }

    val query = sql"SELECT * FROM products WHERE #$sqlFragment".as[Product]

    db.run(query).map { products =>
      Ok(views.html.products(products))
    }.recover {
      case e: Exception => InternalServerError(s"An error occurred: ${e.getMessage}")
    }
  }
}